  1	import * as React from 'react';
  2	import { NetworkType, NADSelectorType } from '@odf/core/types';
  3	import { NetworkAttachmentDefinitionModel } from '@odf/shared';
  4	import {
  5	  getName,
  6	  getUID,
  7	  NetworkAttachmentDefinitionKind,
  8	  SingleSelectDropdown,
  9	  useCustomTranslation,
 10	  useDeepCompareMemoize,
 11	} from '@odf/shared';
 12	import { multusSetupDoc } from '@odf/shared/constants/doc';
 13	import { DOC_VERSION as odfDocVersion } from '@odf/shared/hooks';
 14	import { referenceForModel } from '@odf/shared/utils';
 15	import { ViewDocumentation } from '@odf/shared/utils/doc-utils';
 16	import {
 17	  K8sResourceCommon,
 18	  ResourceIcon,
 19	  useK8sWatchResources,
 20	  WatchK8sResults,
 21	} from '@openshift-console/dynamic-plugin-sdk';
 22	import * as _ from 'lodash-es';
 23	import {
 24	  Alert,
 25	  AlertVariant,
 26	  Checkbox,
 27	  Form,
 28	  FormGroup,
 29	  SelectOption,
 30	} from '@patternfly/react-core';
 31	import { WizardState } from '../../reducer';
 32	
 33	type MultusWatchResourcesObject = {
 34	  multus: NetworkAttachmentDefinitionKind[];
 35	  openshift: NetworkAttachmentDefinitionKind[];
 36	  default: NetworkAttachmentDefinitionKind[];
 37	};
 38	
 39	const k8sToSelectResourceMapper = (
 40	  item: NetworkAttachmentDefinitionKind
 41	): JSX.Element => {
 42	  const uid = getUID(item);
 43	  return (
 44	    <SelectOption id={getName(item)} key={uid} value={uid}>
 45	      <ResourceIcon
 46	        groupVersionKind={{
 47	          group: NetworkAttachmentDefinitionModel.apiGroup,
 48	          version: NetworkAttachmentDefinitionModel.apiVersion,
 49	          kind: NetworkAttachmentDefinitionModel.kind,
 50	        }}
 51	      />
 52	      {getName(item)}
 53	    </SelectOption>
 54	  );
 55	};
 56	
 57	type MultusNetworkConfigurationComponentProps = {
 58	  setNetworkType: any;
 59	  networkType: NetworkType;
 60	  setNetwork: (type: NADSelectorType, resource: K8sResourceCommon) => void;
 61	  clusterNetwork: NetworkAttachmentDefinitionKind;
 62	  publicNetwork: NetworkAttachmentDefinitionKind;
 63	  systemNamespace: WizardState['backingStorage']['systemNamespace'];
 64	  isMultusAcknowledged: boolean;
 65	  setIsMultusAcknowledged: (val: boolean) => void;
 66	};
 67	
 68	const reduceResourceLoadAndErrorStatus = <
 69	  T extends keyof MultusWatchResourcesObject,
 70	>(
 71	  acc: { loaded: boolean; error: any },
 72	  curr: WatchK8sResults<MultusWatchResourcesObject>[T]
 73	) => {
 74	  const loadValue = curr.loaded && acc.loaded;
 75	  const errorValue = curr.loadError || acc.error;
 76	  return { loaded: loadValue, error: errorValue };
 77	};
 78	type MultusDropdownProps = {
 79	  setNetwork: (type: NADSelectorType, resource: K8sResourceCommon) => void;
 80	  clusterNetwork: NetworkAttachmentDefinitionKind;
 81	  publicNetwork: NetworkAttachmentDefinitionKind;
 82	  systemNamespace: WizardState['backingStorage']['systemNamespace'];
 83	};
 84	
 85	export const MultusNetworkConfigurationComponent: React.FC<
 86	  MultusNetworkConfigurationComponentProps
 87	> = ({
 88	  setNetworkType,
 89	  setNetwork,
 90	  clusterNetwork,
 91	  publicNetwork,
 92	  networkType,
 93	  systemNamespace,
 94	  isMultusAcknowledged,
 95	  setIsMultusAcknowledged,
 96	}) => {
 97	  const { t } = useCustomTranslation();
 98	
 99	  const handleMultusToggle = (_event: any, checked: any) => {
100	    if (checked) {
101	      setNetworkType(NetworkType.MULTUS);
102	    } else {
103	      setNetworkType(NetworkType.DEFAULT);
104	      setIsMultusAcknowledged(false);
105	    }
106	  };
107	
108	  const handleAcknowledgementChange = (_event: any, checked: boolean) => {
109	    setIsMultusAcknowledged(checked);
110	  };
111	
112	  return (
113	    <FormGroup fieldId="isoloate-network" label={t('Network isolation')}>
114	      <Checkbox
115	        isChecked={networkType === NetworkType.MULTUS}
116	        onChange={handleMultusToggle}
117	        label={t('Isolate network using Multus')}
118	        id="multus-checkbox"
119	        className="pf-v6-u-mb-md"
120	      />
121	
122	      {networkType === NetworkType.MULTUS && (
123	        <>
124	          <Alert
125	            className="pf-v6-u-ml-md"
126	            variant={AlertVariant.warning}
127	            isInline
128	            title={t('Run Validation test before to proceed further.')}
129	          >
130	            <p>
131	              {t('To run the tool, follow the steps provided in the')}{' '}
132	              <ViewDocumentation
133	                doclink={multusSetupDoc(odfDocVersion)}
134	                text={t('Multus prerequisites validation tool')}
135	                padding="0"
136	              />{' '}
137	              {t(
138	                'section of the documentation. Incorrectly setting up Multus might lead to:'
139	              )}
140	            </p>
141	            <ul>
142	              <li>
143	                {t(
144	                  'Data unavailability or loss due to broken internal communication between storage components.'
145	                )}
146	              </li>
147	              <li>
148	                {t(
149	                  'Cluster health issues if network attachments are missing or misconfigured.'
150	                )}
151	              </li>
152	              <li>
153	                {t(
154	                  'PVC mounting failures, impacting workloads that rely on DF storage.'
155	                )}
156	              </li>
157	            </ul>
158	          </Alert>
159	
160	          <Checkbox
161	            isChecked={isMultusAcknowledged}
162	            label={t(
163	              'By checking this box, you are acknowledging to have run the validation test.'
164	            )}
165	            onChange={handleAcknowledgementChange}
166	            id="acknowledgment-checkbox"
167	            className="pf-v6-u-ml-md pf-v6-u-mt-md"
168	          />
169	        </>
170	      )}
171	      {isMultusAcknowledged && (
172	        <div className="pf-v6-u-ml-md pf-v6-u-mt-md">
173	          <MultusDropdown
174	            setNetwork={setNetwork}
175	            clusterNetwork={clusterNetwork}
176	            publicNetwork={publicNetwork}
177	            systemNamespace={systemNamespace}
178	          />
179	        </div>
180	      )}
181	    </FormGroup>
182	  );
183	};
184	
185	const resources = (ns: string) => ({
186	  openshift: {
187	    isList: true,
188	    kind: referenceForModel(NetworkAttachmentDefinitionModel),
189	    namespace: ns,
190	    namespaced: true,
191	  },
192	  default: {
193	    isList: true,
194	    kind: referenceForModel(NetworkAttachmentDefinitionModel),
195	    namespace: 'default',
196	    namespaced: true,
197	  },
198	  multus: {
199	    isList: true,
200	    kind: referenceForModel(NetworkAttachmentDefinitionModel),
201	    namespace: 'openshift-multus',
202	    namespaced: true,
203	  },
204	});
205	
206	export const MultusDropdown: React.FC<MultusDropdownProps> = ({
207	  setNetwork,
208	  clusterNetwork,
209	  publicNetwork,
210	  systemNamespace,
211	}) => {
212	  const { t } = useCustomTranslation();
213	
214	  const clusterNetworkUID = getUID(clusterNetwork);
215	  const publicNetworkUID = getUID(publicNetwork);
216	
217	  const networkResources = useK8sWatchResources(resources(systemNamespace));
218	
219	  const networkDevices: K8sResourceCommon[] = React.useMemo(() => {
220	    const { loaded: resourcesLoaded, error: resourcesLoadError } =
221	      Object.values(networkResources).reduce(reduceResourceLoadAndErrorStatus, {
222	        loaded: true,
223	        error: null,
224	      });
225	
226	    if (resourcesLoaded && !resourcesLoadError) {
227	      const devices = _.flatMap(
228	        Object.values(networkResources),
229	        (res) => res.data
230	      );
231	      return devices;
232	    }
233	    return [];
234	  }, [networkResources]);
235	
236	  const memoizedNetworkDevices = useDeepCompareMemoize(networkDevices, true);
237	
238	  const selectOptions: JSX.Element[] = React.useMemo(
239	    () => memoizedNetworkDevices.map(k8sToSelectResourceMapper),
240	    [memoizedNetworkDevices]
241	  );
242	
243	  const filter = React.useCallback(
244	    (_unused, textInput: string) => {
245	      if (!textInput) {
246	        return selectOptions;
247	      } else {
248	        return selectOptions.filter((item) =>
249	          (item.props.id as string).toLowerCase().includes(textInput)
250	        );
251	      }
252	    },
253	    [selectOptions]
254	  );
255	
256	  const onSelectPublicNetwork = React.useCallback(
257	    (uid: string) => {
258	      if (!(uid === publicNetworkUID)) {
259	        const resource = memoizedNetworkDevices.find(
260	          (res) => getUID(res) === uid
261	        );
262	        setNetwork(NADSelectorType.PUBLIC, resource);
263	      } else {
264	        setNetwork(NADSelectorType.PUBLIC, null);
265	      }
266	    },
267	    [memoizedNetworkDevices, setNetwork, publicNetworkUID]
268	  );
269	
270	  const onSelectClusterNetwork = React.useCallback(
271	    (uid: string) => {
272	      if (!(uid === clusterNetworkUID)) {
273	        const resource = memoizedNetworkDevices.find(
274	          (res) => getUID(res) === uid
275	        );
276	        setNetwork(NADSelectorType.CLUSTER, resource);
277	      } else {
278	        setNetwork(NADSelectorType.CLUSTER, null);
279	      }
280	    },
281	    [memoizedNetworkDevices, setNetwork, clusterNetworkUID]
282	  );
283	
284	  return (
285	    <Form className="pf-v6-u-font-weight-normal">
286	      <FormGroup
287	        fieldId="configure-multus-public"
288	        label={
289	          <span className="pf-v6-u-font-weight-normal">
290	            {t('Public Network Interface')}
291	          </span>
292	        }
293	      >
294	        <SingleSelectDropdown
295	          id="multus-public-network-dropdown"
296	          onChange={onSelectPublicNetwork}
297	          selectOptions={selectOptions}
298	          selectedKey={publicNetworkUID}
299	          className="ceph__multus-dropdown"
300	          placeholderText={t('Select NetworkAttachmentDefinition')}
301	          onFilter={filter}
302	          hasInlineFilter
303	        />
304	      </FormGroup>
305	      <FormGroup
306	        fieldId="configure-multus-cluster"
307	        label={
308	          <span className="pf-v6-u-font-weight-normal">
309	            {t('Cluster Network Interface')}
310	          </span>
311	        }
312	      >
313	        <SingleSelectDropdown
314	          id="multus-cluster-network-dropdown"
315	          onChange={onSelectClusterNetwork}
316	          selectOptions={selectOptions}
317	          selectedKey={clusterNetworkUID}
318	          className="ceph__multus-dropdown"
319	          placeholderText={t('Select NetworkAttachmentDefinition')}
320	          onFilter={filter}
321	          hasInlineFilter
322	        />
323	      </FormGroup>
324	    </Form>
325	  );
326	};

